import React from 'react';

const AirportParkingLayout = ({ slots, userBookingCount, book, SlotItem }) => {
    // Distribute slots sequentially into 3 chunks for Blocks A, B, C
    const totalSlots = slots.length;
    const chunkSize = Math.ceil(totalSlots / 3);

    const blockA = slots.slice(0, chunkSize);
    const blockB = slots.slice(chunkSize, chunkSize * 2);
    const blockC = slots.slice(chunkSize * 2);

    // Custom inline wrapper for slots to force 45-degree angled herringbone styling over the standard SlotItem
    const AngledSlotWrapper = ({ s, disabled = false }) => {
        return (
            <div style={{
                transform: 'skewX(-20deg)',
                margin: '10px 5px',
                position: 'relative'
            }}>
                <div style={{
                    transform: 'skewX(20deg)', // Un-skew the inner content so text remains readable
                    width: '100%', height: '100%'
                }}>
                    {/* Inject custom blue border or ADA styling strictly at CSS layer if disabled, but use standard SlotItem logic */}
                    <div className={`airport-slot ${disabled ? 'ada-slot' : ''}`}>
                         <SlotItem s={s} userBookingCount={userBookingCount} book={book} />
                         {disabled && (
                             <div style={{ position: 'absolute', top: '-15px', right: '-10px', fontSize: '1.2rem', color: '#1d4ed8', background: 'white', borderRadius: '50%', width: '24px', height: '24px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 2px 5px rgba(0,0,0,0.2)' }}>
                                 <i className="fa-brands fa-accessible-icon"></i>
                             </div>
                         )}
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div style={{
            background: '#333333', // Deep asphalt
            padding: '40px',
            borderRadius: '20px',
            fontFamily: 'monospace',
            position: 'relative',
            boxShadow: 'inset 0 0 50px rgba(0,0,0,0.5)',
            border: '8px solid #4ade80' // Outer Grass edge
        }}>
            {/* Terminal Header */}
            <div style={{
                background: '#e2e8f0',
                padding: '20px',
                textAlign: 'center',
                fontWeight: '900',
                fontSize: '1.5rem',
                color: '#0f172a',
                border: '4px solid #94a3b8',
                borderRadius: '8px',
                maxWidth: '600px',
                margin: '0 auto 40px auto',
                letterSpacing: '4px',
                boxShadow: '0 10px 20px rgba(0,0,0,0.3)'
            }}>
                <i className="fa-solid fa-plane-departure" style={{ marginRight: '10px' }}></i>
                AIRPORT TERMINAL
            </div>

            {/* Drop-off Zone */}
            <div style={{
                width: '100%',
                height: '80px',
                borderTop: '2px dashed #94a3b8',
                borderBottom: '2px dashed #94a3b8',
                marginBottom: '40px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                padding: '0 40px',
                background: 'rgba(255,255,255,0.02)'
            }}>
                <span style={{ color: 'white', fontSize: '1.5rem', opacity: 0.8 }}><i className="fa-solid fa-arrow-left"></i> ONE-WAY</span>
                <div style={{
                    background: 'repeating-linear-gradient(45deg, #cbd5e1, #cbd5e1 10px, transparent 10px, transparent 20px)',
                    width: '300px', height: '60px',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    backgroundOrigin: 'border-box'
                }}>
                    <span style={{ background: '#333', color: 'white', padding: '4px 12px', borderRadius: '4px', fontWeight: 'bold' }}>DROP-OFF / PICK-UP ZONE</span>
                </div>
                <span style={{ color: 'white', fontSize: '1.5rem', opacity: 0.8 }}>ONE-WAY <i className="fa-solid fa-arrow-right"></i></span>
            </div>

            {/* Parking Blocks Engine */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '40px' }}>

                {/* BLOCK A */}
                <div style={{
                    background: '#262626',
                    border: '6px solid #4ade80', // Grass border
                    borderRadius: '40px',
                    padding: '30px',
                    position: 'relative'
                }}>
                    <div style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 'bold', fontSize: '1.2rem', marginBottom: '20px', letterSpacing: '2px' }}>
                        PARKING BLOCK A
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                        {blockA.map(s => <AngledSlotWrapper key={s._id} s={s} />)}
                    </div>
                    <div style={{ textAlign: 'center', color: 'white', marginTop: '20px', fontSize: '2rem', opacity: 0.5 }}>
                        <i className="fa-solid fa-arrow-up"></i>
                    </div>
                </div>

                {/* BLOCK B (Includes Disabled/ADA Slots on Top) */}
                <div style={{
                    background: '#262626',
                    border: '6px solid #4ade80',
                    borderRadius: '40px',
                    padding: '30px',
                    position: 'relative'
                }}>
                    <div style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 'bold', fontSize: '1.2rem', marginBottom: '20px', letterSpacing: '2px' }}>
                        PARKING BLOCK B
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                        {blockB.map((s, idx) => (
                            <AngledSlotWrapper key={s._id} s={s} disabled={idx < 4} />
                        ))}
                    </div>
                    <div style={{ textAlign: 'center', color: 'white', marginTop: '20px', fontSize: '2rem', opacity: 0.5 }}>
                        <i className="fa-solid fa-arrow-up"></i>
                    </div>
                </div>

                {/* BLOCK C */}
                <div style={{
                    background: '#262626',
                    border: '6px solid #4ade80',
                    borderRadius: '40px',
                    padding: '30px',
                    position: 'relative'
                }}>
                    <div style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 'bold', fontSize: '1.2rem', marginBottom: '20px', letterSpacing: '2px' }}>
                        PARKING BLOCK C
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                        {blockC.map(s => <AngledSlotWrapper key={s._id} s={s} />)}
                    </div>
                    <div style={{ textAlign: 'center', color: 'white', marginTop: '20px', fontSize: '2rem', opacity: 0.5 }}>
                        <i className="fa-solid fa-arrow-up"></i>
                    </div>
                </div>

            </div>

            {/* Bottom Road Marking  */}
            <div style={{
                marginTop: '40px',
                display: 'flex',
                justifyContent: 'space-between',
                padding: '0 40px',
                color: 'white',
                opacity: 0.8,
                fontSize: '1.5rem',
                fontWeight: 'bold',
                alignItems: 'center'
            }}>
                <div>ENTRY <i className="fa-solid fa-arrow-right"></i></div>
                <div><i className="fa-solid fa-arrow-right"></i></div>
                <div><i className="fa-solid fa-arrow-right"></i> EXIT</div>
            </div>

            {/* Global Styled Injection for this specific Component overriding the children strictly */}
            <style jsx="true">{`
                .ada-slot > div {
                    border-color: #3b82f6 !important;
                    background: rgba(59, 130, 246, 0.1) !important;
                }
            `}</style>
        </div>
    );
};

export default AirportParkingLayout;
